"use client"

import * as React from "react"
import { Check, ChevronsUpDown, Search, X } from "lucide-react"
import { Checkbox } from "@/components/lemma/ui/checkbox"
import { Input } from "@/components/lemma/ui/input"
import { Label } from "@/components/lemma/ui/label"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/lemma/ui/popover"
import { Select, SelectContent, SelectGroup, SelectItem, SelectTrigger, SelectValue } from "@/components/lemma/ui/select"
import { Textarea } from "@/components/lemma/ui/textarea"
import { useForeignKeyOptions } from "lemma-sdk/react"
import type { ColumnSchema, LemmaClient } from "lemma-sdk"
import { cn } from "@/components/lemma/lib/utils"

export type SharedRecordFormRadius = "none" | "sm" | "md" | "lg" | "xl"

export interface SharedRecordFormFieldDescriptor {
  name: string
  label: string
  kind: string
  column: ColumnSchema
  required?: boolean
  options?: string[]
}

export interface RecordFormFieldProps {
  field: SharedRecordFormFieldDescriptor
  value: unknown
  error?: string
  onChange: (value: unknown) => void
  client: LemmaClient
  podId?: string
  tableName: string
  labelField?: string
  radius?: SharedRecordFormRadius
  getRadiusClassName?: (radius: SharedRecordFormRadius, target: "surface" | "control" | "pill") => string
}

export interface RecordFieldInputProps {
  field: SharedRecordFormFieldDescriptor
  value: unknown
  onChange: (value: unknown) => void
  client: LemmaClient
  podId?: string
  tableName: string
  labelField?: string
  radius?: SharedRecordFormRadius
  getRadiusClassName?: (radius: SharedRecordFormRadius, target: "surface" | "control" | "pill") => string
  controlSize?: "sm" | "md"
  controlClassName?: string
  disabled?: boolean
  onBlur?: React.FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement | HTMLTextAreaElement>
}

export function RecordFormField({
  field,
  value,
  error,
  onChange,
  client,
  podId,
  tableName,
  labelField,
  radius = "lg",
  getRadiusClassName = defaultRadiusClassName,
}: RecordFormFieldProps) {
  const displayLabel = field.label || field.name.replace(/_/g, " ")

  return (
    <div className="space-y-1.5">
      <div className="flex items-center gap-2">
        <Label className="text-xs font-semibold uppercase tracking-widest text-muted-foreground">
          {displayLabel}
          {field.required && <span className="ml-0.5 text-destructive">*</span>}
        </Label>
        <span className={typeBadgeClassName(field.column, radius, getRadiusClassName)}>
          {field.column.foreign_key ? "ref" : field.column.type.toLowerCase()}
        </span>
      </div>

      <RecordFieldInput
        field={field}
        value={value}
        onChange={onChange}
        client={client}
        podId={podId}
        tableName={tableName}
        labelField={labelField}
        radius={radius}
        getRadiusClassName={getRadiusClassName}
      />

      {error ? <p className="text-xs text-destructive">{error}</p> : null}
    </div>
  )
}

export function RecordFieldInput({
  field,
  value,
  onChange,
  client,
  podId,
  tableName,
  labelField,
  radius = "lg",
  getRadiusClassName = defaultRadiusClassName,
  controlSize = "md",
  controlClassName,
  disabled,
  onBlur,
  onKeyDown,
}: RecordFieldInputProps) {
  const fkOptions = useForeignKeyOptions({
    client,
    podId,
    tableName,
    columnName: field.name,
    labelField,
    enabled: field.kind === "foreign-key",
  })

  const displayLabel = field.label || field.name.replace(/_/g, " ")
  const rawValue = value
  const stringValue = resolveFieldStringValue(value)
  const selectedForeignKeyLabel = resolveFieldOptionLabel(value)
    ?? fkOptions.options.find((opt) => String(opt.value) === stringValue)?.label
  const controlBaseClassName = buildControlClassName(controlSize, radius, getRadiusClassName, controlClassName)
  const textAreaRows = field.kind === "json" ? 4 : 3

  if (field.kind === "foreign-key") {
    return (
      <SearchableValueSelect
        value={stringValue}
        selectedLabel={selectedForeignKeyLabel}
        options={fkOptions.options}
        placeholder="Select…"
        searchPlaceholder={`Search ${displayLabel.toLowerCase()}...`}
        radius={radius}
        getRadiusClassName={getRadiusClassName}
        controlSize={controlSize}
        controlClassName={controlClassName}
        disabled={disabled}
        onChange={(nextValue) => onChange(nextValue || null)}
      />
    )
  }

  if (field.kind === "select" && field.options?.length) {
    return (
      <Select value={stringValue || undefined} onValueChange={(nextValue) => onChange(nextValue)} disabled={disabled}>
        <SelectTrigger className={controlBaseClassName}>
          <SelectValue placeholder="Select…" />
        </SelectTrigger>
        <SelectContent>
          <SelectGroup>
            {field.options.map((option) => (
              <SelectItem key={option} value={option}>{option}</SelectItem>
            ))}
          </SelectGroup>
        </SelectContent>
      </Select>
    )
  }

  if (field.kind === "boolean") {
    return (
      <div className={cn("flex items-center gap-2", controlSize === "sm" ? "h-8" : "h-9")}>
        <Checkbox checked={isCheckedValue(rawValue)} disabled={disabled} onCheckedChange={(checked) => onChange(checked === true)} />
        <span className="text-sm text-muted-foreground">{isCheckedValue(rawValue) ? "Yes" : "No"}</span>
      </div>
    )
  }

  if (field.kind === "textarea") {
    return (
      <Textarea
        value={stringValue}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value)}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        rows={textAreaRows}
        className={cn("resize-none placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
      />
    )
  }

  if (field.kind === "number") {
    return (
      <Input
        type="number"
        value={stringValue}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value)}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        className={cn("placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
      />
    )
  }

  if (field.kind === "date") {
    return (
      <Input
        type="date"
        value={stringValue}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value || null)}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        className={cn("placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
      />
    )
  }

  if (field.kind === "datetime") {
    return (
      <Input
        type="datetime-local"
        value={stringValue}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value || null)}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        className={cn("placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
      />
    )
  }

  if (field.kind === "json") {
    return (
      <Textarea
        value={stringValue}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value)}
        onBlur={onBlur}
        onKeyDown={onKeyDown}
        rows={textAreaRows}
        className={cn("resize-none font-mono text-xs placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
        placeholder="{}"
      />
    )
  }

  return (
    <Input
      type="text"
      value={stringValue}
      disabled={disabled}
      onChange={(event) => onChange(event.target.value)}
      onBlur={onBlur}
      onKeyDown={onKeyDown}
      className={cn("placeholder:text-muted-foreground focus-ring", controlBaseClassName)}
      placeholder={displayLabel}
    />
  )
}

function SearchableValueSelect({
  value,
  selectedLabel,
  options,
  placeholder,
  searchPlaceholder,
  radius,
  getRadiusClassName,
  controlSize,
  controlClassName,
  disabled,
  onChange,
}: {
  value: string
  selectedLabel?: string
  options: Array<{ value: unknown; label: string }>
  placeholder: string
  searchPlaceholder: string
  radius: SharedRecordFormRadius
  getRadiusClassName: (radius: SharedRecordFormRadius, target: "surface" | "control" | "pill") => string
  controlSize: "sm" | "md"
  controlClassName?: string
  disabled?: boolean
  onChange: (value: string | null) => void
}) {
  const [open, setOpen] = React.useState(false)
  const [query, setQuery] = React.useState("")

  const filteredOptions = React.useMemo(() => {
    const needle = query.trim().toLowerCase()
    if (!needle) return options
    return options.filter((option) =>
      option.label.toLowerCase().includes(needle) || String(option.value).toLowerCase().includes(needle),
    )
  }, [options, query])

  return (
    <Popover
      open={open}
      onOpenChange={(nextOpen) => {
        setOpen(nextOpen)
        if (!nextOpen) setQuery("")
      }}
    >
      <PopoverTrigger
        type="button"
        disabled={disabled}
        className={cn(
          "inline-flex w-full items-center justify-between gap-3 px-3 text-sm transition-colors hover:bg-muted disabled:pointer-events-none disabled:opacity-60",
          buildControlClassName(controlSize, radius, getRadiusClassName, controlClassName),
        )}
      >
        <span className="min-w-0 flex-1 truncate text-left">
          {selectedLabel ?? (value ? shortenIdentifier(value) : <span className="text-muted-foreground">{placeholder}</span>)}
        </span>
        <ChevronsUpDown className="size-3.5 shrink-0 text-muted-foreground" />
      </PopoverTrigger>
      <PopoverContent align="start" className={cn("w-[var(--radix-popper-anchor-width)] min-w-72 p-0", getRadiusClassName(radius, "surface"))}>
        <div className="border-b border-border/40 p-2">
          <div className="relative">
            <Search className="absolute left-2.5 top-1/2 size-3.5 -translate-y-1/2 text-muted-foreground" />
            <Input
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder={searchPlaceholder}
              className={cn("pl-8 text-xs", buildControlClassName("sm", radius, getRadiusClassName, controlClassName))}
            />
          </div>
        </div>
        <div className="max-h-72 overflow-auto p-1">
          {value ? (
            <button
              type="button"
              className={cn("flex w-full items-center gap-2 px-2 py-2 text-left text-sm text-muted-foreground hover:bg-muted/45", getRadiusClassName(radius, "control"))}
              onClick={() => {
                onChange(null)
                setOpen(false)
                setQuery("")
              }}
            >
              <X className="size-4" />
              Clear selection
            </button>
          ) : null}
          {filteredOptions.length === 0 ? (
            <div className="flex min-h-24 items-center justify-center text-sm text-muted-foreground">
              No options found
            </div>
          ) : (
            filteredOptions.map((option) => {
              const selected = String(option.value) === value
              return (
                <button
                  key={String(option.value)}
                  type="button"
                  className={cn("flex w-full items-center gap-2 px-2 py-2 text-left text-sm hover:bg-muted/45", getRadiusClassName(radius, "control"), selected ? "bg-muted/60" : null)}
                  onClick={() => {
                    onChange(String(option.value))
                    setOpen(false)
                    setQuery("")
                  }}
                >
                  <span className="min-w-0 flex-1 truncate">{option.label}</span>
                  {selected ? <Check className="size-4 text-primary" /> : null}
                </button>
              )
            })
          )}
        </div>
      </PopoverContent>
    </Popover>
  )
}

function typeBadgeClassName(
  column: ColumnSchema,
  radius: SharedRecordFormRadius,
  getRadiusClassName: (radius: SharedRecordFormRadius, target: "surface" | "control" | "pill") => string,
) {
  const typeTints: Record<string, { bg: string; text: string }> = {
    TEXT: { bg: "bg-muted/45", text: "text-muted-foreground" },
    INTEGER: { bg: "bg-emerald-500/10", text: "text-emerald-700 dark:text-emerald-300" },
    FLOAT: { bg: "bg-blue-500/10", text: "text-blue-700 dark:text-blue-300" },
    BOOLEAN: { bg: "bg-primary/10", text: "text-primary" },
    DATE: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
    DATETIME: { bg: "bg-amber-500/10", text: "text-amber-700 dark:text-amber-300" },
    ENUM: { bg: "bg-violet-500/10", text: "text-violet-700 dark:text-violet-300" },
    JSON: { bg: "bg-rose-500/10", text: "text-rose-700 dark:text-rose-300" },
    UUID: { bg: "bg-sky-500/10", text: "text-sky-700 dark:text-sky-300" },
  }

  const tint = column.foreign_key
    ? { bg: "bg-sky-500/10", text: "text-sky-700 dark:text-sky-300" }
    : typeTints[column.type] ?? typeTints.TEXT

  return cn(
    "border border-border/50 px-1.5 py-0.5 text-[9px] font-medium normal-case",
    tint.bg,
    tint.text,
    getRadiusClassName(radius, "pill"),
  )
}

function resolveFieldStringValue(value: unknown): string {
  if (value == null) return ""
  if (typeof value === "object" && value !== null && !Array.isArray(value)) {
    const objectValue = value as Record<string, unknown>
    if (objectValue.id != null) return String(objectValue.id)
  }
  return String(value)
}

function resolveFieldOptionLabel(value: unknown): string | undefined {
  if (typeof value !== "object" || value == null || Array.isArray(value)) return undefined

  const objectValue = value as Record<string, unknown>
  const label = objectValue.name ?? objectValue.title ?? objectValue.label
  return label != null ? String(label) : undefined
}

function isCheckedValue(value: unknown): boolean {
  return value === true || value === "true" || value === 1 || value === "1"
}

function shortenIdentifier(value: unknown): string {
  const text = String(value ?? "")
  if (!text) return "—"
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(text)) {
    return `${text.slice(0, 8)}…${text.slice(-4)}`
  }
  return text.length > 28 ? `${text.slice(0, 24)}…` : text
}

function defaultRadiusClassName(
  radius: SharedRecordFormRadius = "lg",
  target: "surface" | "control" | "pill" = "surface",
): string {
  if (radius === "none") return "rounded-none"
  if (radius === "sm") return target === "surface" ? "rounded-md" : "rounded-sm"
  if (radius === "md") return "rounded-md"
  if (radius === "xl") return target === "surface" ? "rounded-2xl" : target === "control" ? "rounded-xl" : "rounded-full"
  return target === "surface" ? "rounded-xl" : target === "control" ? "rounded-lg" : "rounded-full"
}

function buildControlClassName(
  controlSize: "sm" | "md",
  radius: SharedRecordFormRadius,
  getRadiusClassName: (radius: SharedRecordFormRadius, target: "surface" | "control" | "pill") => string,
  controlClassName?: string,
) {
  return cn(
    controlSize === "sm" ? "h-8" : "h-9",
    "border-border bg-background",
    getRadiusClassName(radius, "control"),
    controlClassName,
  )
}

"use client"

import * as React from "react"
import { Loader2 } from "lucide-react"
import { Button } from "@/components/lemma/ui/button"
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/lemma/ui/dialog"
import { Sheet, SheetContent, SheetDescription, SheetHeader, SheetTitle } from "@/components/lemma/ui/sheet"
import { Separator } from "@/components/lemma/ui/separator"
import { useRecordForm } from "lemma-sdk/react"
import {
  DEFAULT_RECORD_FORM_HIDDEN_FIELDS,
  orderRecordSchemaFields,
  type LemmaClient,
} from "lemma-sdk"
import { RecordFormField } from "@/components/lemma/record-form-fields"
import { cn } from "@/components/lemma/lib/utils"

export type LemmaRecordFormAppearance = "default" | "minimal" | "borderless" | "contained"
export type LemmaRecordFormSurface = "inherit" | "muted" | "card"
export type LemmaRecordFormDensity = "compact" | "comfortable" | "spacious"
export type LemmaRecordFormRadius = "none" | "sm" | "md" | "lg" | "xl"
export type LemmaRecordFormVisibilityRule<TContext> = boolean | ((context: TContext) => boolean)

export interface LemmaRecordFormFieldVisibilityContext {
  values: Record<string, unknown>
  fieldName: string
}

export interface LemmaRecordFormSectionVisibilityContext {
  values: Record<string, unknown>
  label: string
  fields: string[]
}

export interface LemmaRecordFormFieldGroup {
  label: string
  fields: string[]
  visible?: LemmaRecordFormVisibilityRule<LemmaRecordFormSectionVisibilityContext>
}

export interface LemmaRecordFormProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string

  mode?: "inline" | "modal" | "sheet"
  surface?: LemmaRecordFormSurface
  appearance?: LemmaRecordFormAppearance
  density?: LemmaRecordFormDensity
  radius?: LemmaRecordFormRadius
  submitVia?: "direct" | "function"
  submitFunctionName?: string
  submitFunctionInput?: (payload: Record<string, unknown>) => Record<string, unknown>
  hiddenFields?: string[]
  visibleFields?: string[]
  fieldOrder?: string[]
  fieldGroups?: LemmaRecordFormFieldGroup[]
  fieldVisibility?: Record<string, LemmaRecordFormVisibilityRule<LemmaRecordFormFieldVisibilityContext>>
  sectionVisibility?: Record<string, LemmaRecordFormVisibilityRule<LemmaRecordFormSectionVisibilityContext>>
  foreignKeyLabels?: Record<string, string>

  initialValues?: Record<string, unknown>
  onSuccess?: (record: Record<string, unknown>) => void
  onClose?: () => void
}

export function LemmaRecordForm({
  client,
  podId,
  tableName,
  recordId,
  mode = "inline",
  surface,
  appearance = "default",
  density = "comfortable",
  radius = "lg",
  submitVia = "direct",
  submitFunctionName,
  submitFunctionInput,
  hiddenFields = [],
  visibleFields,
  fieldOrder,
  fieldGroups,
  fieldVisibility,
  sectionVisibility,
  foreignKeyLabels,
  initialValues,
  onSuccess,
  onClose,
}: LemmaRecordFormProps) {
  const form = useRecordForm({
    client,
    podId,
    tableName,
    recordId: recordId || null,
    hiddenFields: [...hiddenFields, ...DEFAULT_RECORD_FORM_HIDDEN_FIELDS],
    visibleFields,
    submitVia,
    submitFunctionName,
    submitFunctionInput,
    onSubmitSuccess: (record) => onSuccess?.(record),
    initialValues,
  })

  const isEdit = !!recordId
  const title = isEdit ? "Edit Record" : "New Record"
  const resolvedSurface = surface ?? (appearance === "borderless" ? "inherit" : appearance === "minimal" ? "muted" : "card")

  const orderedFields = React.useMemo(() => {
    return orderRecordSchemaFields(form.editableFields, fieldOrder)
  }, [form.editableFields, fieldOrder])
  const visibleOrderedFields = React.useMemo(() => {
    return orderedFields.filter((field) =>
      resolveVisibility(fieldVisibility?.[field.name], {
        values: form.values,
        fieldName: field.name,
      }),
    )
  }, [fieldVisibility, form.values, orderedFields])
  const visibleFieldGroups = React.useMemo(() => {
    if (!fieldGroups?.length) return null

    return fieldGroups
      .filter((group) => {
        const context = { values: form.values, label: group.label, fields: group.fields }
        return resolveVisibility(group.visible, context) && resolveVisibility(sectionVisibility?.[group.label], context)
      })
      .map((group) => ({
        ...group,
        fields: group.fields.filter((fieldName) => visibleOrderedFields.some((field) => field.name === fieldName)),
      }))
      .filter((group) => group.fields.length > 0)
  }, [fieldGroups, form.values, sectionVisibility, visibleOrderedFields])

  const renderField = React.useCallback(
    (field: typeof orderedFields[number]) => (
      <RecordFormField
        key={field.name}
        field={field}
        value={form.values[field.name]}
        error={form.fieldErrors[field.name]}
        onChange={(nextValue) => form.setValue(field.name, nextValue)}
        client={client}
        podId={podId}
        tableName={tableName}
        labelField={foreignKeyLabels?.[field.name]}
        radius={radius}
        getRadiusClassName={formRadiusClassName}
      />
    ),
    [client, foreignKeyLabels, form, podId, radius, tableName],
  )

  const inner = (
    <div className="flex h-full min-h-0 flex-col">
      {mode === "modal" && (
        <DialogHeader className={cn("shrink-0", formHeaderClassName(resolvedSurface, density))}>
          <DialogTitle className="text-lg font-semibold tracking-tight">{title}</DialogTitle>
          <DialogDescription>{tableName}</DialogDescription>
        </DialogHeader>
      )}

      {mode === "sheet" && (
        <SheetHeader className={cn("shrink-0", formHeaderClassName(resolvedSurface, density))}>
          <SheetTitle className="text-lg font-semibold tracking-tight">{title}</SheetTitle>
          <SheetDescription>{tableName}</SheetDescription>
        </SheetHeader>
      )}

      <div className={cn("flex-1 overflow-y-auto", formBodyClassName(density))}>
        {form.isLoadingSchema ? (
          <div className="flex items-center justify-center py-12 text-sm text-muted-foreground">
            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            Loading schema…
          </div>
        ) : visibleFieldGroups ? (
          <div className={cn("flex flex-col", density === "compact" ? "gap-4" : density === "spacious" ? "gap-7" : "gap-6")}>
            {visibleFieldGroups.map((group, gi) => (
              <div key={gi}>
                <p className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground mb-3">
                  {group.label}
                </p>
                <div className={cn("flex flex-col", density === "compact" ? "gap-3" : density === "spacious" ? "gap-5" : "gap-4")}>
                  {group.fields
                    .map((fieldName) => orderedFields.find((field) => field.name === fieldName))
                    .filter((field): field is typeof orderedFields[number] => Boolean(field))
                    .map(renderField)}
                </div>
                {gi < visibleFieldGroups.length - 1 && <Separator className="mt-6 bg-border/30" />}
              </div>
            ))}
          </div>
        ) : (
          <div className={cn("flex flex-col", density === "compact" ? "gap-3" : density === "spacious" ? "gap-5" : "gap-4")}>
            {visibleOrderedFields.map(renderField)}
          </div>
        )}

        {form.error && (
          <p className="mt-4 rounded-md border border-destructive/30 bg-destructive/10 px-3 py-2 text-sm text-destructive">
            {form.error.message}
          </p>
        )}
      </div>

      <div className={cn("shrink-0", formFooterClassName(resolvedSurface, density))}>
        <div className="flex items-center justify-end gap-3">
          {onClose && (
            <Button variant="ghost" onClick={onClose}>
              Cancel
            </Button>
          )}
          <Button
            onClick={() => form.submit()}
            disabled={form.isSubmitting || form.isLoadingSchema}
          >
            {form.isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {isEdit ? "Save Changes" : "Create"}
          </Button>
        </div>
      </div>
    </div>
  )

  if (mode === "sheet") {
    return (
      <Sheet open onOpenChange={(open) => !open && onClose?.()}>
        <SheetContent
          className={cn("!h-full !w-[calc(100vw-1rem)] !max-w-[60rem] gap-0 p-0", formSurfaceClassName(resolvedSurface, radius))}
        >
          {inner}
        </SheetContent>
      </Sheet>
    )
  }

  if (mode === "modal") {
    return (
      <Dialog open onOpenChange={(open) => !open && onClose?.()}>
        <DialogContent
          className={cn("!h-[92vh] !max-h-[92vh] !w-[calc(100vw-2rem)] !max-w-[72rem] gap-0 overflow-hidden p-0", formSurfaceClassName(resolvedSurface, radius))}
        >
          {inner}
        </DialogContent>
      </Dialog>
    )
  }

  return <div className={cn(resolvedSurface === "inherit" ? "bg-transparent" : resolvedSurface === "muted" ? "bg-transparent" : "bg-card", formSurfaceClassName(resolvedSurface, radius))}>{inner}</div>
}

function formHeaderClassName(surface: LemmaRecordFormSurface, density: LemmaRecordFormDensity) {
  return cn(
    surface === "inherit" ? "border-b-0" : surface === "muted" ? "border-b border-border/15" : "border-b border-border/50",
    density === "compact" ? "px-4 py-3" : density === "spacious" ? "px-7 py-5" : "px-6 py-4",
  )
}

function formBodyClassName(density: LemmaRecordFormDensity) {
  if (density === "compact") return "px-4 py-3"
  if (density === "spacious") return "px-7 py-6"
  return "px-6 py-4"
}

function formFooterClassName(surface: LemmaRecordFormSurface, density: LemmaRecordFormDensity) {
  return cn(
    surface === "inherit"
      ? "border-t-0 bg-transparent"
      : surface === "muted"
        ? "border-t border-border/15 bg-transparent"
        : "border-t border-border/50 bg-muted/30",
    density === "compact" ? "px-4 py-2.5" : density === "spacious" ? "px-7 py-4" : "px-6 py-3",
  )
}

function formSurfaceClassName(surface: LemmaRecordFormSurface, radius: LemmaRecordFormRadius) {
  const radiusClassName = formRadiusClassName(radius, "surface")
  if (surface === "inherit") return cn(radiusClassName, "border-0 bg-transparent shadow-none ring-0")
  if (surface === "muted") return cn(radiusClassName, "border-0 bg-background/70 shadow-none ring-1 ring-border/15")
  return cn(radiusClassName, "border border-border/50")
}

function resolveVisibility<TContext>(
  rule: LemmaRecordFormVisibilityRule<TContext> | undefined,
  context: TContext,
): boolean {
  if (typeof rule === "boolean") return rule
  if (typeof rule === "function") return rule(context)
  return true
}

function formRadiusClassName(
  radius: LemmaRecordFormRadius = "lg",
  target: "surface" | "control" | "pill" = "surface",
): string {
  if (radius === "none") return "rounded-none"
  if (radius === "sm") return target === "surface" ? "rounded-md" : "rounded-sm"
  if (radius === "md") return "rounded-md"
  if (radius === "xl") return target === "surface" ? "rounded-2xl" : target === "control" ? "rounded-xl" : "rounded-full"
  return target === "surface" ? "rounded-xl" : target === "control" ? "rounded-lg" : "rounded-full"
}
